/// <summary>
/// Gets or sets the fractional refresh-policy distribution for runs in this period.
/// Each run contributes exactly 1.0, split proportionally by per-node effective refresh policy.
/// The sum of <see cref="RefreshPolicyDistribution.Full"/> + <see cref="RefreshPolicyDistribution.Incremental"/>
/// + <see cref="RefreshPolicyDistribution.NoRefresh"/> equals the number of runs in this period
/// that had at least one refresh-eligible node.
/// </summary>

string runDate = await reader.IsDBNullAsync(runDateOrd, cancellationToken)
    ? null
    : reader.GetString(runDateOrd);

/// <summary>
/// Maps the current row of a positioned <see cref="DbDataReader"/> to a <see cref="DailyTrendEntry"/>.
/// Uses <see cref="DbDataReader"/> (abstract base of <see cref="SqlDataReader"/>) so the mapping
/// can be unit-tested with a mocked reader — same pattern as <see cref="MapSummaryResponseAsync"/>.
/// Fraction values are <see cref="Math.Round(double, int)"/>-rounded to 1 decimal to match the
/// summary endpoint's <see cref="RefreshPolicyDistribution"/> precision.
/// </summary>

Assert.IsTrue(query.Contains("SUM(COALESCE(fraction_full, 0)) AS fractionFull"), "Day query should SUM(COALESCE) fraction_full.");
Assert.IsTrue(query.Contains("SUM(COALESCE(fraction_incremental, 0)) AS fractionIncremental"), "Day query should SUM(COALESCE) fraction_incremental.");
Assert.IsTrue(query.Contains("SUM(COALESCE(fraction_no_refresh, 0)) AS fractionNoRefresh"), "Day query should SUM(COALESCE) fraction_no_refresh.");

Assert.IsTrue(query.Contains("SUM(COALESCE(fraction_full, 0)) AS fractionFull"), "Week query should SUM(COALESCE) fraction_full.");
Assert.IsTrue(query.Contains("SUM(COALESCE(fraction_incremental, 0)) AS fractionIncremental"), "Week query should SUM(COALESCE) fraction_incremental.");
Assert.IsTrue(query.Contains("SUM(COALESCE(fraction_no_refresh, 0)) AS fractionNoRefresh"), "Week query should SUM(COALESCE) fraction_no_refresh.");
